import{_ as d,C as a,o as i,c as s,j as t,a as o,E as n,ag as c}from"./chunks/framework.HG0H2VLS.js";const f=JSON.parse('{"title":"FilterBar","description":"","frontmatter":{},"headers":[],"relativePath":"patterns/filter-bar.md","filePath":"patterns/filter-bar.md"}'),l={name:"patterns/filter-bar.md"};function h(p,e,g,b,u,m){const r=a("ComponentDemo");return i(),s("div",null,[e[0]||(e[0]=t("hr",null,null,-1)),e[1]||(e[1]=t("h2",{id:"title-filterbar",tabindex:"-1"},[o("title: FilterBar "),t("a",{class:"header-anchor",href:"#title-filterbar","aria-label":'Permalink to "title: FilterBar"'},"​")],-1)),e[2]||(e[2]=t("h1",{id:"filterbar",tabindex:"-1"},[o("FilterBar "),t("a",{class:"header-anchor",href:"#filterbar","aria-label":'Permalink to "FilterBar"'},"​")],-1)),n(r,{src:"/demos/src/patterns/FilterBar/FilterBar.html"}),e[3]||(e[3]=c('<h2 id="characteristics" tabindex="-1">Characteristics <a class="header-anchor" href="#characteristics" aria-label="Permalink to &quot;Characteristics&quot;">​</a></h2><ul><li><strong>Two rows</strong> (border between): row 1 saved-views + Export + search/kebab, row 2 chips.</li><li><strong>Export</strong> is an explicit <code>btn--secondary</code> button in row 1.</li><li>Chips use the <strong>solid Default</strong> FilterItem treatment (only &quot;Add Filters&quot; is dashed), all <code>--rounded</code>.</li><li>Views trigger text is <strong>regular</strong> weight.</li><li><strong>Search mode</strong> replaces row 1 only — the chips row stays.</li><li><strong>Mobile:</strong> Export collapses out of the bar; chips wrap; search has icon+takeover or the Alt Search inline field.</li></ul><h2 id="variant-matrix-8-type-×-desktop-mobile-alt-search-mobile" tabindex="-1">Variant matrix (8 Type × Desktop/Mobile, + Alt Search mobile) <a class="header-anchor" href="#variant-matrix-8-type-×-desktop-mobile-alt-search-mobile" aria-label="Permalink to &quot;Variant matrix (8 Type × Desktop/Mobile, + Alt Search mobile)&quot;">​</a></h2><p><code>Type</code> = scenarios of one toolbar (modelled as JS modes + composed-component states).</p><table tabindex="0"><thead><tr><th>Node ID (Desktop / Mobile)</th><th>Type</th><th>Representation</th></tr></thead><tbody><tr><td>2977:3803 / 2977:3804</td><td>Default</td><td>base markup (solid chips)</td></tr><tr><td>2977:3801 / 2977:3810</td><td>Filter Active</td><td>a chip carries <code>.filter-item--selected</code></td></tr><tr><td>2977:3797 / 2977:3808</td><td>Views dropdown</td><td>saved-views <code>.dropdown</code> is <code>.is-open</code></td></tr><tr><td>2977:3799 / 2977:3806</td><td>New View</td><td>root <code>.filter-bar--new-view</code></td></tr><tr><td>2977:3798 / 2977:3802</td><td>Wrapping</td><td>more chips → row 2 flex-wraps</td></tr><tr><td>2989:6121 / 2989:6242</td><td>Save View</td><td>root <code>.filter-bar--save-view</code> reveals a &quot;Save view&quot; primary CTA (Button, sm) pinned right of row 2; Add Filters rejoins the chip flow</td></tr><tr><td>2977:3800 / 2977:3809</td><td>Search</td><td>root <code>.filter-bar--search</code></td></tr><tr><td>— / 2999:4699</td><td>Alt Search (mobile)</td><td>root <code>.filter-bar--alt-search</code> — <strong>mobile-only</strong> alternative to the search icon + takeover: a persistent search field fills row 1 between the views control and the kebab</td></tr><tr><td>2977:3807 / 2977:3805</td><td>Actions</td><td>kebab <code>.dropdown</code> is <code>.is-open</code></td></tr></tbody></table><p>Desktop fetched in full: Default, New View, Search. The rest are state/content permutations.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li>Outer: <code>flex-direction: column</code>, <code>background: surface-primary</code>, border-secondary, radius-md. <strong>No <code>overflow: hidden</code></strong> — the root&#39;s own bg + radius round the card and the inter-row divider sits mid-card, so nothing needs clipping; clipping would crop the saved-views / kebab dropdown panels (which must escape the card).</li><li><strong>Row 1</strong> (<code>.filter-bar__row--top</code>, <code>border-bottom</code>): <code>[lead (views) .....16px..... [Export · Search · kebab]]</code>, px <code>--ai-spacing-5</code> / py <code>--ai-spacing-4</code>. <strong>Export, the search field, and the kebab are grouped in the <code>.filter-bar__actions</code> div</strong> (Figma row-1 &quot;Frame 230&quot;, e.g. 2989:6122) with an internal <code>--ai-spacing-3</code> (8px) gap; the row&#39;s <code>--ai-spacing-5</code> (16px) gap only separates the lead from that group. The <strong>search is a persistent 192px field</strong> (<code>--ai-size-3</code>) on desktop (Figma 2977:3803).</li><li><strong>Row 2</strong>: <code>[chips (flex-1, wrap) — &quot;Add Filters&quot; is the last chip in the flow]</code>, same padding. (In the Save View state a &quot;Save view&quot; CTA sits as a sibling after <code>__chips</code>, pinned right.)</li><li><strong>Search responsive behaviour:</strong> desktop shows the persistent <code>.filter-bar__search-bar</code> field + hides the search icon; <strong>mobile (≤767px)</strong> hides the field and shows the <strong>search icon</strong>, which enters the full-width <strong>takeover</strong> (<code>--search</code> mode → back-arrow + <code>.filter-bar__search</code> in lead). Implemented mobile-first: <code>.filter-bar__search-bar { display:none }</code>, then <code>@media (min-width:768px)</code> shows it (192px) and hides <code>.filter-bar__icon-btn[aria-label=&quot;Search&quot;]</code>.</li><li><strong>Mobile (≤767px):</strong> rows already stack; the <strong>Export button is hidden</strong> (<code>display:none</code>) per the Figma mobile variants; the <strong>chips row wraps</strong> to multiple lines (Figma mobile variant 2977:3804). The <strong>New View &quot;Create&quot; CTA uses the small button</strong> at mobile (<code>btn--sm</code> sizing applied to <code>.filter-bar__create</code> in the media query — padding <code>--ai-spacing-4</code>, <code>min-height --ai-spacing-7</code>, <code>font-size --ai-font-fluid-xxs</code>), per Figma mobile New View variant 2977:3806 (<code>button/sm</code>). Desktop keeps <code>button/base</code>.</li></ul><h2 id="modes-js-—-filterbar-js" tabindex="-1">Modes (JS — FilterBar.js) <a class="header-anchor" href="#modes-js-—-filterbar-js" aria-label="Permalink to &quot;Modes (JS — FilterBar.js)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Class</th><th>Effect</th></tr></thead><tbody><tr><td>Search</td><td><code>.filter-bar--search</code></td><td>row 1 → back-arrow + full-width search Input (Export + actions hidden); <strong>chips row 2 stays</strong></td></tr><tr><td>New View</td><td><code>.filter-bar--new-view</code></td><td>row 1 views → &quot;New view&quot; Input + Create (Export + actions stay); <strong>row 2 collapses to just Add Filters</strong>. <strong>Create</strong> (<code>new-view-create</code>) appends the typed name to the saved-views list (<code>addView</code>, flagged <code>data-view-empty=&quot;1&quot;</code>) + selects it (<code>selectView</code>) + re-wires its … (<code>Dropdown.initAll</code>); <strong>×</strong> cancels. A new (empty) view shows <strong>only &quot;Add Filters&quot;</strong> via <code>.filter-bar--view-empty</code> (non-destructive — chips stay in the DOM). Existing views keep their default chips; <code>selectView</code> toggles <code>--view-empty</code> from the row&#39;s flag, so switching back restores them.</td></tr><tr><td>Alt Search</td><td><code>.filter-bar--alt-search</code></td><td><strong>mobile-only</strong> alternative search treatment (Figma 2999:4699). Instead of the search icon + full-width takeover, the persistent <code>.filter-bar__search-bar</code> field is shown and <strong>fills</strong> row 1 (<code>flex:1</code>) between the views control and the kebab. The views trigger becomes a <strong>plain borderless control</strong> (<code>width:auto</code>, no border / bg / padding — not the 192px field) so the search gets the width; row-1 gap is <code>--ai-spacing-5</code> (16px) between the views control and the search field. Search icon hidden. Desktop unchanged. CSS-only (modifier on the root).</td></tr><tr><td>Save View</td><td><code>.filter-bar--save-view</code></td><td>a filter added/amended — <strong>mock</strong>: clicking the &quot;Add Filters&quot; chip (FilterItem bubbles <code>filter-item:toggle</code> with <code>open:true</code>) reveals the <code>.filter-bar__save</code> &quot;Save view&quot; CTA (Button <code>--primary --sm</code>) — the last child <strong>inside</strong> <code>__chips</code>, after &quot;Add Filters&quot;. <strong>Desktop:</strong> <code>margin-left:auto</code> pins it to the right edge of the chip row. <strong>Mobile (≤767px):</strong> that margin is dropped so it flows right after &quot;Add Filters&quot; in the wrapping chips (Figma mobile 2989:6242). Clicking the CTA (<code>data-filter-action=&quot;save-view&quot;</code>) is a mock &quot;save&quot; — drops the class + closes the Add Filters chip. <strong>TODO(backend:Filters)</strong> — real trigger is a persisted filter-set change.</td></tr></tbody></table><p><strong>Saved-view selection + rename</strong> (<code>FilterBar.js</code> <code>wireViews</code> —: double-click OR the <strong>&quot;Rename&quot; item in the row&#39;s … menu</strong> (<code>[data-filter-rename]</code>, beside Copy/Delete) runs an inline <code>.filter-bar__rename</code> overlay; capture-phase click takeover + 220ms single/double disambiguation; the … is on every row incl. the selected one and is always-visible on touch via <code>@media (hover: none)</code> in <code>Dropdown.css</code>; code-first, not in Figma — flag for designer) and the <strong>right-aligned kebab panel</strong> (<code>.filter-bar__menu .dropdown__panel { left:auto; right:0 }</code>). The search field lives inside <code>__lead</code> (which stays visible in search mode), so it needs no relocation.</p><h2 id="backend-handover" tabindex="-1">Backend handover <a class="header-anchor" href="#backend-handover" aria-label="Permalink to &quot;Backend handover&quot;">​</a></h2><p><code>TODO(backend:Filters)</code> — see <code>HANDOVER.md</code> → Surface: Filters (shared with FilterItem).</p><h2 id="css-classes" tabindex="-1">CSS Classes <a class="header-anchor" href="#css-classes" aria-label="Permalink to &quot;CSS Classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Class</th><th>Notes</th></tr></thead><tbody><tr><td>Root</td><td><code>.filter-bar</code></td><td>column, border-secondary, radius-md, overflow hidden</td></tr><tr><td>Row</td><td><code>.filter-bar__row</code> (+<code>--top</code>)</td><td>flex, gap 16, pad 12/16; <code>--top</code> adds bottom border</td></tr><tr><td>Lead (row 1)</td><td><code>.filter-bar__lead</code></td><td>flex-1, gap 8 — holds views / new-view / search</td></tr><tr><td>Views control</td><td><code>.dropdown.filter-bar__views</code></td><td>Dropdown filter-views panel; trigger field is <strong>regular</strong> weight</td></tr><tr><td>Actions</td><td><code>.filter-bar__actions</code></td><td>row-1 group (Figma &quot;Frame 230&quot;), 8px gap: <strong>Export</strong> + persistent search field (desktop) / search icon-btn (mobile) + kebab <code>.dropdown</code></td></tr><tr><td>Export</td><td><code>.btn.btn--secondary.filter-bar__export</code></td><td>first child of <code>.filter-bar__actions</code>; Button + <code>download</code> icon; hidden on mobile</td></tr><tr><td>Search field (desktop)</td><td><code>.input.filter-bar__search-bar</code></td><td>persistent 192px Input; desktop only — replaced by the icon + takeover on mobile</td></tr><tr><td>Chips (row 2)</td><td><code>.filter-bar__chips</code></td><td>flex-wrap, gap 8; chips are FilterItem <strong>default (solid)</strong> / <code>--selected</code>, <strong>all <code>--rounded</code></strong> (pill <code>--ai-radius-full</code>, per user direction)</td></tr><tr><td>Add Filters</td><td><code>.filter-item--empty.filter-item--rounded.filter-bar__add</code></td><td>dashed pill; <strong>last chip inside <code>__chips</code></strong> (in the flow, after the filter list)</td></tr><tr><td>Save view CTA</td><td><code>.btn.btn--primary.btn--sm.filter-bar__save</code></td><td>composes Button (primary, sm); hidden until <code>.filter-bar--save-view</code>, then pinned right of row 2</td></tr><tr><td>Search / New-view / Create / Back</td><td><code>.filter-bar__{search,new-view,create,back}</code></td><td>compose Input / Button</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><p>Token set: surface-primary, border-secondary, spacing-3/4/5/8, size-3, radius-md, icon-contrast, icon-size-sm, font-body/fixed-xs/leading-md). The views trigger uses <code>--ai-font-regular</code>. Export button uses the Button component&#39;s <code>--ai-btn-secondary-*</code> tokens. Selected chips use <code>--ai-surface-info-soft</code> / <code>--ai-border-info</code> via the FilterItem component.</p><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None for the shell. Documented Figma artifact: the &quot;Add Filters&quot; <strong>MinimalBadge</strong> uses raw <code>#364153</code> (Gray/700) — replaced here with a proper <strong>FilterItem <code>--empty</code></strong> (<code>--ai-text-primary</code>). Outer frame width is <code>970px</code> in Figma (no token) — built <strong>fluid</strong> (<code>width: 100%</code>, consumer-controlled), so the arbitrary 970 is not hardcoded.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Composition: Dropdown-as-views-trigger, Input search, no invented hover/focus (WCAG <code>:focus-visible</code> only).</li><li>Export icon: Figma &quot;Icon/24px/Export&quot; (tray + down arrow) → Lucide <strong><code>download</code></strong>.</li></ul>',21))])}const v=d(l,[["render",h]]);export{f as __pageData,v as default};
